// ─── Types ────────────────────────────────────────────────────────────────────

export interface Seat {
  id: string;
  status: "available" | "reserved";
  userId?: string;
}

export interface Reservation {
  seatId: string;
  userId: string;
  reservedAt: Date;
}

export interface Database {
  findSeat(seatId: string): Promise<Seat | null>;
  /**
   * Atomically update the seat status.
   * Returns true  if the row was updated  (current status matched expectedCurrentStatus).
   * Returns false if the row was NOT updated (optimistic-lock conflict — another writer won).
   */
  updateSeatStatus(
    seatId: string,
    status: string,
    userId: string,
    expectedCurrentStatus: string
  ): Promise<boolean>;
}

// ─── Error codes ──────────────────────────────────────────────────────────────

export type ReservationErrorCode = "SEAT_NOT_FOUND" | "SEAT_ALREADY_RESERVED";

export class ReservationError extends Error {
  readonly code: ReservationErrorCode;

  constructor(code: ReservationErrorCode, message: string) {
    super(message);
    this.name = "ReservationError";
    this.code = code;
  }
}

// ─── Implementation ───────────────────────────────────────────────────────────

export async function reserveSeat(
  seatId: string,
  userId: string,
  db: Database
): Promise<Reservation> {
  // AC4: seat must exist
  const seat = await db.findSeat(seatId);
  if (seat === null) {
    throw new ReservationError("SEAT_NOT_FOUND", `Seat ${seatId} does not exist`);
  }

  // AC2: fast-path check — seat already reserved at read time
  if (seat.status !== "available") {
    throw new ReservationError(
      "SEAT_ALREADY_RESERVED",
      `Seat ${seatId} is already reserved`
    );
  }

  // AC1 + AC3: attempt atomic update — only succeeds if status is still 'available'
  // This is the optimistic-lock guard that prevents double-reservations under concurrency.
  const updated = await db.updateSeatStatus(seatId, "reserved", userId, "available");

  if (!updated) {
    // Another concurrent call won the race between our findSeat read and this update.
    throw new ReservationError(
      "SEAT_ALREADY_RESERVED",
      `Seat ${seatId} was reserved by another request`
    );
  }

  return {
    seatId,
    userId,
    reservedAt: new Date(),
  };
}

